1	<script lang="ts">
2		import { Loader2 } from 'lucide-svelte';
3		import { projectStore } from '$lib/stores/project.svelte';
4		import { nodeStore } from '$lib/stores/node.svelte';
5		import { createClient } from '$lib/gql/client';
6		import { subscribeBeadLifecycle, subscribeWorkerProgress } from '$lib/gql/subscriptions';
7		import { gql } from 'graphql-request';
8	
9		// Persistent drain-queue worker indicator (ddx-b6cf025c). Shown on every
10		// route inside a selected project; hidden when no project is selected.
11		// Subscription-driven so worker-state changes reflect within 2s
12		// (workerProgress) and bead-count changes within 5s (beadLifecycle).
13		// A 3s poll backstops both in case events are dropped.
14	
15		const SUMMARY_QUERY = gql`
16			query QueueAndWorkersSummary($projectId: String!) {
17				queueAndWorkersSummary(projectId: $projectId) {
18					readyBeads
19					runningWorkers
20					totalWorkers
21				}
22			}
23		`;
24	
25		const RUNNING_WORKERS_QUERY = gql`
26			query DrainIndicatorRunningWorkers($projectID: String!) {
27				workersByProject(projectID: $projectID, first: 50) {
28					edges {
29						node {
30							id
31							state
32						}
33					}
34				}
35			}
36		`;
37	
38		let readyBeads = $state(0);
39		let runningWorkers = $state(0);
40		let loaded = $state(false);
41	
42		const projectId = $derived(projectStore.value?.id ?? null);
43		const nodeId = $derived(nodeStore.value?.id ?? null);
44		const workersHref = $derived(
45			nodeId && projectId ? `/nodes/${nodeId}/projects/${projectId}/workers` : null
46		);
47		const active = $derived(runningWorkers > 0);
48	
49		const label = $derived.by(() => {
50			if (!loaded) return '';
51			if (active) {
52				const w = runningWorkers === 1 ? 'worker' : 'workers';
53				return `${runningWorkers} ${w} · ${readyBeads} ready`;
54			}
55			return `Queue: ${readyBeads} ready`;
56		});
57	
58		async function refresh(pid: string) {
59			try {
60				const client = createClient(fetch);
61				const data = await client.request<{
62					queueAndWorkersSummary: {
63						readyBeads: number;
64						runningWorkers: number;
65						totalWorkers: number;
66					};
67				}>(SUMMARY_QUERY, { projectId: pid });
68				readyBeads = data.queueAndWorkersSummary.readyBeads;
69				runningWorkers = data.queueAndWorkersSummary.runningWorkers;
70				loaded = true;
71			} catch {
72				// Keep previous values on transient failure. AC #4: "falls back to the
73				// global count" is handled implicitly by holding state; we intentionally
74				// do not clear `loaded` so the badge keeps rendering.
75			}
76		}
77	
78		async function fetchRunningWorkerIds(pid: string): Promise<string[]> {
79			try {
80				const client = createClient(fetch);
81				const data = await client.request<{
82					workersByProject: { edges: { node: { id: string; state: string } }[] };
83				}>(RUNNING_WORKERS_QUERY, { projectID: pid });
84				return data.workersByProject.edges
85					.filter((e) => e.node.state === 'running')
86					.map((e) => e.node.id);
87			} catch {
88				return [];
89			}
90		}
91	
92		$effect(() => {
93			const pidNullable = projectId;
94			if (!pidNullable) {
95				loaded = false;
96				return;
97			}
98			const pid: string = pidNullable;
99			let cancelled = false;
100			const workerSubs = new Map<string, () => void>();
101	
102			async function rewireWorkerSubscriptions() {
103				if (cancelled) return;
104				const ids = await fetchRunningWorkerIds(pid);
105				if (cancelled) return;
106				const next = new Set(ids);
107				// Drop subscriptions for workers no longer running.
108				for (const [id, dispose] of workerSubs) {
109					if (!next.has(id)) {
110						dispose();
111						workerSubs.delete(id);
112					}
113				}
114				// Add subscriptions for newly-running workers.
115				for (const id of ids) {
116					if (workerSubs.has(id)) continue;
117					const dispose = subscribeWorkerProgress(id, () => {
118						void refresh(pid);
119					});
120					workerSubs.set(id, dispose);
121				}
122			}
123	
124			void refresh(pid).then(() => void rewireWorkerSubscriptions());
125	
126			// Bead lifecycle drives both ready-count freshness AND triggers a re-scan
127			// for new running workers (workers come online by claiming a bead, which
128			// fires status_changed).
129			const beadDispose = subscribeBeadLifecycle(pid, () => {
130				void refresh(pid);
131				void rewireWorkerSubscriptions();
132			});
133	
134			const h = setInterval(() => {
135				void refresh(pid);
136				void rewireWorkerSubscriptions();
137			}, 3000);
138	
139			return () => {
140				cancelled = true;
141				clearInterval(h);
142				beadDispose();
143				for (const dispose of workerSubs.values()) dispose();
144				workerSubs.clear();
145			};
146		});
147	</script>
